mapper.select:
SELECT * FROM recharge_order
WHERE user_id = #{userId} AND deleted = 0
ORDER BY id DESC LIMIT #{offset}, #{size}

SELECT ro.*, u.nickname, u.phone
FROM recharge_order ro
LEFT JOIN `user` u ON u.id = ro.user_id AND u.deleted = 0
WHERE ro.deleted = 0
AND u.store_id = #{storeId}
AND ro.recharge_no = #{rechargeNo}
AND ro.status = #{status}
ORDER BY ro.id DESC LIMIT #{offset}, #{size}

SELECT COUNT(*)
FROM recharge_order ro
LEFT JOIN `user` u ON u.id = ro.user_id AND u.deleted = 0
WHERE ro.deleted = 0
AND u.store_id = #{storeId}
AND ro.recharge_no = #{rechargeNo}
AND ro.status = #{status}
